const transformSocialUserData = (user: GoogleUserProps | MicrosoftUserProps): TransformedUser => {
  if (!user.email) throw new Error('no_email_found');

  const normalizedEmail = user.email.toLowerCase().trim();

  const givenName = 'given_name' in user ? user.given_name : user.givenname || '';
  const familyName = 'family_name' in user ? user.family_name : user.familyname || '';
  const name = user.name || `${givenName} ${familyName}`.trim();

  return {
    id: user.sub,
    slug: slugFromEmail(normalizedEmail),
    email: normalizedEmail,
    name: name,
    emailVerified: 'email_verified' in user ? user.email_verified : false,
    thumbnailUrl: user.picture,
    firstName: givenName,
    lastName: familyName,
  };
};

app.openapi(authOAuthRoutes.github, async (ctx) => {
  // Check if Github OAuth is enabled
  const strategy = 'github' as EnabledOAuthProvider;

  if (!appConfig.enabledAuthStrategies.includes('oauth') || !appConfig.enabledOAuthProviders.includes(strategy)) {
    throw new AppError(400, 'unsupported_oauth', 'error', {
      willRedirect: appConfig.mode !== 'test',
      meta: { errorPagePath: '/auth/error', strategy },
    });
  }

  // Generate a `state` to prevent CSRF, and build URL with scope.
  const state = generateState();
  const url = githubAuth.createAuthorizationURL(state, githubScopes);

  // Start the OAuth session & flow (Persist `state`)
  return await handleOAuthInitiation(ctx, 'github', url, state);
});

app.openapi(authTotpsRoutes.deleteTotp, async (ctx) => {
  const user = ctx.var.user;

  // Remove TOTP and conditionally disable MFA atomically
  await baseDb.transaction(async (tx) => {
    await tx.delete(totpsTable).where(eq(totpsTable.userId, user.id));

    // Check if the user still has any passkeys or TOTP entries registered
    const { passkeys, totps } = await findRemainingMfaMethods({ var: { ...ctx.var, db: tx } }, { userId: user.id });

    // MFA requires both passkeys and TOTP as backup — disable if either is missing
    if (!passkeys.length || !totps.length) {
      await disableMfa({ var: { ...ctx.var, db: tx } }, { userId: user.id });
    }
  });

  sendAccountSecurityEmail(ctx, user, 'totp-removed');

  return ctx.body(null, 204);
});

if (cursor) {
  const activityResults = await findDeleteAndMembershipActivities(dbCtx, cursor, organizationIdArray, [
    ...appConfig.productEntityTypes,
  ]);

  for (const row of activityResults) {
    if (!row.organizationId || !changes[row.organizationId]) continue;

    // Membership activity — org entry already exists, client will invalidate membership queries
    if (row.resourceType === 'membership') continue;

    // Product entity delete
    if (!row.subjectId || !row.entityType) continue;
    const scope = changes[row.organizationId];
    if (!scope.deletedByType[row.entityType]) scope.deletedByType[row.entityType] = [];
    scope.deletedByType[row.entityType].push(row.subjectId);
  }
}

if (resolvedCursor) {
  const deletedResults = await findPublicDeleteActivities(dbCtx, resolvedCursor, publicTypes);

  for (const row of deletedResults) {
    if (!row.entityType || !row.subjectId) continue;

    // Ensure entityType has a changes entry (may not have one if only deletes happened)
    if (!changes[row.entityType]) {
      const serverSeq = serverSeqs.get(row.entityType) ?? 0;
      changes[row.entityType] = {
        deletedByType: {},
        entitySeqs: { [row.entityType]: serverSeq },
      };
    }

    if (!changes[row.entityType].deletedByType[row.entityType])
      changes[row.entityType].deletedByType[row.entityType] = [];
    changes[row.entityType].deletedByType[row.entityType].push(row.subjectId);
  }
}

const buildSubject = (
  entityType: ContextEntityType | ProductEntityType,
  source: Partial<ContextEntityIdColumns>,
  options?: { id?: string; createdBy?: string | null },
): SubjectForPermission => {
  const subject: SubjectForPermission = {
    entityType,
    id: options?.id ?? generateId(),
    ...(options?.createdBy !== undefined && { createdBy: options.createdBy }),
  } as SubjectForPermission;

  for (const ancestor of hierarchy.getOrderedAncestors(entityType)) {
    const idKey = appConfig.entityIdColumnKeys[ancestor];
    const value = source[idKey as keyof ContextEntityIdColumns];
    if (value !== undefined) {
      (subject as Record<string, unknown>)[idKey] = value;
    }
  }

  validateAncestorScope(subject);

  return subject;
};

const getValidSingleUseToken = async ({ ctx, tokenType }: Props): Promise<TokenModel> => {
  // Find single use token in cookie
  const singleUseToken = await getAuthCookie(ctx, tokenType);
  if (!singleUseToken) throw new AppError(400, 'invalid_token', 'warn');

  // Get token record that matches type and singleUseToken value
  const [tokenRecord] = await db
    .select()
    .from(tokensTable)
    .where(and(eq(tokensTable.type, tokenType), eq(tokensTable.singleUseToken, singleUseToken)))
    .limit(1);

  if (!tokenRecord) throw new AppError(404, `${tokenType}_not_found`, 'error');

  // Token expired
  if (isExpiredDate(tokenRecord.expiresAt)) {
    throw new AppError(401, `${tokenRecord.type}_expired`, 'warn');
  }

  return tokenRecord;
};

