const sitemapPlugin = ({
  baseUrl,
  canonicalize = true,
}: SitemapPluginOptions): SSGPlugin => {
  return {
    afterGenerateHook: async (result, fsModule, options) => {
      const outputDir = options?.dir ?? DEFAULT_OUTPUT_DIR
      const filePath = path.join(outputDir, 'sitemap.xml')

      const urls = result.files
        .filter((file) => file.endsWith('.html'))
        .map((file) => canonicalizeFilePath(file, outputDir, baseUrl, canonicalize).url)

      const siteMapText = `<?xml version="1.0" encoding="UTF-8"?>
<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">
${urls.map((url) => `<url><loc>${url}</loc></url>`).join('\n')}
</urlset>
`
      await fsModule.writeFile(filePath, siteMapText)
    },
  }
}

const SwaggerUI = ({ baseUrl, version, ...options }: SwaggerUIOptions): string => {
  const asset = remoteAssets({
    baseUrl: baseUrl,
    version: version,
  })

  if (options.manuallySwaggerUIHtml) {
    return options.manuallySwaggerUIHtml(asset)
  }

  const optionsStrings = renderSwaggerUIOptions(options)

  return `
    <div>
      <div id="swagger-ui"></div>
      ${asset.css.map((url) => html`<link rel="stylesheet" href="${url}" />`)}
      ${asset.js.map((url) => html`<script src="${url}" crossorigin="anonymous"></script>`)}
      <script>
        window.onload = () => {
          window.ui = SwaggerUIBundle({
            dom_id: '#swagger-ui',${optionsStrings},
          })
        }
      </script>
    </div>
  `
}

return validator(target, (unprocessedData, c) => {
    const data = useClean ? compiled.Clean(unprocessedData) : unprocessedData

    if (compiled.Check(data)) {
      if (hook) {
        const hookResult = hook({ success: true, data }, c)
        if (hookResult instanceof Response || hookResult instanceof Promise) {
          return hookResult
        }
      }
      return data
    }

    const errors = compiled.Errors(data)
    if (hook) {
      const hookResult = hook({ success: false, errors }, c)
      if (hookResult instanceof Response || hookResult instanceof Promise) {
        return hookResult
      }
    }

    return c.json({ success: false, errors }, 400)
  }) as MiddlewareHandler<E, P, V>

for (const rawScheme of Object.values(securitySchemes)) {
  const scheme = getResolvedRef(rawScheme)

  // Skip schemes that could not be resolved (e.g. a `$ref` to a missing component)
  if (!scheme || !isOAuth2Scheme(scheme)) {
    continue
  }

  const flows = scheme.flows // Type assertion no longer needed

  // Helper to safely add valid OAuth URLs
  const addOAuthUrl = (url?: string) => {
    if (url && isValidOAuthUrl(url)) {
      oauthUrls.add(getPathFromUrl(url))
    }
  }

  addOAuthUrl(flows?.password?.tokenUrl)
  addOAuthUrl(flows?.password?.refreshUrl)
  addOAuthUrl(flows?.clientCredentials?.tokenUrl)
  addOAuthUrl(flows?.clientCredentials?.refreshUrl)
  addOAuthUrl(flows?.authorizationCode?.tokenUrl)
  addOAuthUrl(flows?.authorizationCode?.refreshUrl)
  addOAuthUrl(flows?.implicit?.refreshUrl)
}

