const projectsWithStatistics = projects.map((project) => {
  const totalTasks = project.tasks.length;
  const completedTasks = project.tasks.filter(
    (task) => task.status === "done" || task.status === "archived",
  ).length;
  const completionPercentage =
    totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

  const dueDate = project.tasks.reduce((earliest: Date | null, task) => {
    if (!earliest || (task.dueDate && task.dueDate < earliest))
      return task.dueDate;
    return earliest;
  }, null);

  return {
    ...project,
    statistics: {
      completionPercentage,
      totalTasks,
      dueDate,
    },
    archivedTasks: [],
    plannedTasks: [],
    columns: [],
  };
});

switch (type) {
  case "status_changed":
    return `changed status from ${toDisplayCase(String(data.oldStatus ?? ""))} to ${toDisplayCase(String(data.newStatus ?? ""))}`;
  case "priority_changed":
    return `changed priority from ${toDisplayCase(String(data.oldPriority ?? ""))} to ${toDisplayCase(String(data.newPriority ?? ""))}`;
  case "unassigned":
    return "unassigned the task";
  case "assignee_changed":
    return data.isSelfAssigned
      ? "assigned the task to themselves"
      : `assigned the task to ${String(data.newAssignee ?? "someone")}`;
  case "due_date_changed":
    if (!data.newDueDate) {
      return "cleared the due date";
    }
    if (!data.oldDueDate) {
      return `set due date to ${String(data.newDueDate)}`;
    }
    return `changed due date from ${String(data.oldDueDate)} to ${String(data.newDueDate)}`;
  case "title_changed":
    return `changed title from "${String(data.oldTitle ?? "")}" to "${String(data.newTitle ?? "")}"`;
  case "task":
    return "created the task";
  default:
    return undefined;
}

if (token) {
  const apiKeyResult = await verifyApiKey(token);
  if (apiKeyResult?.valid && apiKeyResult.key) {
    const key = apiKeyResult.key;
    c.set("userId", key.userId);
    c.set("userEmail", "");
    c.set("user", null);
    c.set("session", null);
    c.set("apiKey", {
      id: key.id,
      userId: key.userId,
      enabled: key.enabled,
    });
    return;
  }
  const sessionResult = await getSessionFromBearerOnlyHeaders(c);
  if (sessionResult?.user && sessionResult.session) {
    c.set("user", sessionResult.user);
    c.set("session", sessionResult.session);
    c.set("userId", sessionResult.user.id);
    c.set("userEmail", sessionResult.user.email ?? "");
    return;
  }
  throw new HTTPException(401, { message: "Unauthorized" });
}
